        let thinkContent = '';
        let inBlockComment = false;

        // ── YAML inline object renderer ──────────────────────────────────────
        function renderYamlObj(objStr) {
          var result = '<span class="yaml-obj">';
          var parts = objStr.split(',');
          for (var i = 0; i < parts.length; i++) {
            var kv = parts[i].trim();
