            if (itemText === '|' || itemText === '>' || itemText === '|-' || itemText === '>-' || itemText === '|' || itemText === '>-') continue;
            html += '<div class="ui-list-item" style="margin-left:' + marginLeft + 'px"><div class="ui-li-line"></div><div class="ui-li-text">' + escHtml(itemText) + '</div></div>';
            continue;
