              else if (inner.charAt(ci) === ']' || inner.charAt(ci) === '}') depth--;
              else if (inner.charAt(ci) === ',' && depth === 0) {
                items.push(inner.substring(last, ci).trim());
                last = ci + 1;
              }
            }
            items.push(inner.substring(last).trim());
            var arrHtml = '<span class="yaml-obj">';
            for (var ai = 0; ai < items.length; ai++) {
              arrHtml += '<span class="yaml-val">' + escHtml(items[ai]) + '</span>';
              if (ai < items.length - 1) arrHtml += '<span class="yaml-sep">, </span>';
            }
            return arrHtml + '</span>';
          }
          return escHtml(v);
        }
